{"path": "/tmp/sv-568aee4e4407437cb3a68b26b2062d47/Components/Pages/Apply/StepIndicator.razor", "file_text": "<div class="d-flex align-items-start justify-content-center mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var isCompleted = stepIndex < CurrentStep;
        var isCurrent = stepIndex == CurrentStep;
        var isFuture = stepIndex > CurrentStep;

        @if (i > 0)
        {
            <div style="width: 40px; height: 2px; margin-top: 18px; background-color: @(i <= CurrentStep ? "#198754" : "#dee2e6");"></div>
        }

        <div class="text-center" style="flex: 0 0 auto; width: 100px; cursor: @(isCompleted ? "pointer" : "default");"
             @onclick="() => OnStepClick(stepIndex)">
            <div class="mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                        @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                 style="width: 36px; height: 36px; font-size: 0.85rem;">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <small class="@(isFuture ? "text-muted" : isCurrent ? "fw-semibold" : "text-success")">@StepNames[stepIndex]</small>
        </div>
    }
</div>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}
"}

{"path": "/tmp/sv-568aee4e4407437cb3a68b26b2062d47/Components/Pages/Apply/PersonalInfoStep.razor", "file_text": "<div>
    <h4 class="mb-3">Personal Information</h4>

    <div class="mb-3">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")" @bind="Model.Email" />
        @if (emailError is not null)
        {
            <div class="invalid-feedback">@emailError</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <textarea class="form-control" rows="2" @bind="Model.Address"></textarea>
    </div>

    @if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <div class="d-flex justify-content-end">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            validationError = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-568aee4e4407437cb3a68b26b2062d47/Components/Pages/Apply/WorkHistoryStep.razor", "file_text": "<div>
    <h4 class="mb-3">Work History</h4>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]" Index="index"
                       CanRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                validationError = "Each position requires at least a company, title, and start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-568aee4e4407437cb3a68b26b2062d47/Components/Pages/Apply/ReferencesStep.razor", "file_text": "<div>
    <h4 class="mb-3">References</h4>
    <p class="text-muted">Please provide 2–3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]" Index="index"
                       CanRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    @if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                validationError = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-568aee4e4407437cb3a68b26b2062d47/Components/Pages/Apply/CoverLetterStep.razor", "file_text": "<div>
    <h4 class="mb-3">Cover Letter</h4>

    <div class="mb-2">
        <textarea class="form-control" rows="12" maxlength="2000"
                  @bind:get="CoverLetter"
                  @bind:set="HandleInput"
                  @bind:event="oninput"></textarea>
    </div>

    <div class="text-muted mb-3">
        @(CoverLetter?.Length ?? 0) / 2000 characters
    </div>

    @if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private async Task HandleInput(string value)
    {
        await CoverLetterChanged.InvokeAsync(value);
    }

    private async Task HandleNext()
    {
        validationError = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            validationError = "Please write a cover letter.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}
"}

