                <dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9 mb-0">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a role="button" class="text-decoration-none" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</a>
        </div>
        <div class="card-body">
            @for (int i = 0; i < WorkEntries.Count; i++)
            {
                var entry = WorkEntries[i];
                if (i > 0)
                {
                    <hr />
                }
                <p class="mb-1 fw-semibold">@entry.Title at @entry.Company</p>
                <p class="mb-1 text-muted">
                    @entry.StartDate?.ToString("MMM yyyy") –
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </p>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0">@entry.Description</p>
                }
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a role="button" class="text-decoration-none" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</a>
        </div>
        <div class="card-body">
            @for (int i = 0; i < References.Count; i++)
            {
                var r = References[i];
                if (i > 0)
                {
                    <hr />
                }
                <p class="mb-1 fw-semibold">@r.Name <span class="fw-normal text-muted">(@r.Relationship)</span></p>
                <p class="mb-0 text-muted">@r.Email &middot; @r.Phone</p>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <a role="button" class="text-decoration-none" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</a>
        </div>
        <div class="card-body">
            <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (errorMessage is not null)
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private bool isSubmitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(Personal.FullName, Personal.Email, Personal.Phone, Personal.Address),
                new WorkHistory(WorkEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate!.Value,
                    e.IsCurrent ? null : e.EndDate, e.Description
                )).ToList()),
                References.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                CoverLetter
            );

            var applicationId = await ApplicationService.SubmitApplicationAsync(application);
            await OnSubmitted.InvokeAsync(applicationId);
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}
"}

{"path": "/tmp/sv-568aee4e4407437cb3a68b26b2062d47/Components/Pages/Apply/Apply.razor", "file_text": "@page "/apply"
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (submittedId is not null)
    {
        <div class="alert alert-success text-center py-5">
            <h4 class="alert-heading">Application Submitted!</h4>
            <p>Your application has been received successfully.</p>
            <hr />
            <p class="mb-0">Your application ID is:</p>
            <p class="display-6 fw-bold mb-0">@submittedId</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" OnStepSelected="GoToStep" />

        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo"
                                  ApplicationService="ApplicationService"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 2:
                <ReferencesStep References="references"
                                OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            ApplicationService="ApplicationService"
                            OnBack="PrevStep"
                            OnEditSection="GoToStep"
                            OnSubmitted="HandleSubmitted" />
                break;
        }
    }
</div>

@code {
    private int currentStep;
    private int? submittedId;

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void NextStep() => currentStep++;
    private void PrevStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private void HandleSubmitted(int applicationId)
    {
        submittedId = applicationId;
    }
}
"}

