toolArgs.file_text:
@page "/apply"
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (submittedId is not null)
    {
        <div class="alert alert-success text-center py-5">
            <h4 class="alert-heading">Application Submitted!</h4>
            <p>Your application has been received successfully.</p>
            <hr />
            <p class="mb-0">Your application ID is:</p>
            <p class="display-6 fw-bold mb-0">@submittedId</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" OnStepSelected="GoToStep" />

        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo"
                                  ApplicationService="ApplicationService"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 2:
                <ReferencesStep References="references"
                                OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            ApplicationService="ApplicationService"
                            OnBack="PrevStep"
                            OnEditSection="GoToStep"
                            OnSubmitted="HandleSubmitted" />
                break;
        }
    }
</div>

@code {
    private int currentStep;
    private int? submittedId;

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void NextStep() => currentStep++;
    private void PrevStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private void HandleSubmitted(int applicationId)
    {
        submittedId = applicationId;
    }
}

